import{_ as o,o as a,c as r,a2 as e}from"./chunks/framework.DS_HIvHc.js";const q=JSON.parse('{"title":"Cowork가 뭔가요?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-cowork.md","filePath":"guide/what-is-cowork.md","lastUpdated":1773902344000}'),s={name:"guide/what-is-cowork.md"};function d(i,t,l,n,u,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="cowork가-뭔가요" tabindex="-1">Cowork가 뭔가요? <a class="header-anchor" href="#cowork가-뭔가요" aria-label="Permalink to &quot;Cowork가 뭔가요?&quot;">​</a></h1><blockquote><p>한 마디로, 내 컴퓨터에서 나와 함께 일하는 AI 동료입니다.</p></blockquote><h2 id="기존-chatgpt-웹-ai와-뭐가-다른가요" tabindex="-1">기존 ChatGPT / 웹 AI와 뭐가 다른가요? <a class="header-anchor" href="#기존-chatgpt-웹-ai와-뭐가-다른가요" aria-label="Permalink to &quot;기존 ChatGPT / 웹 AI와 뭐가 다른가요?&quot;">​</a></h2><p>웹에서 쓰는 AI 챗봇은 <strong>&quot;질문하면 답변하는&quot;</strong> 수준입니다. Cowork는 <strong>&quot;내 파일을 보고, 직접 작업까지 해주는&quot;</strong> 데스크탑 동료예요.</p><table tabindex="0"><thead><tr><th>상황</th><th>웹 AI 챗봇</th><th>Claude Cowork</th></tr></thead><tbody><tr><td>&quot;이 보고서 수정해줘&quot;</td><td>파일을 복사-붙여넣기 해야 함</td><td>내 컴퓨터의 파일을 직접 열어서 수정</td></tr><tr><td>&quot;지난번에 했던 거 이어서&quot;</td><td>새 대화마다 처음부터 설명</td><td>이전 대화와 작업 맥락을 기억</td></tr><tr><td>&quot;이 엑셀 데이터 분석해줘&quot;</td><td>파일 업로드 용량 제한</td><td>내 컴퓨터의 파일에 직접 접근</td></tr><tr><td>&quot;회의록 정리해서 공유해줘&quot;</td><td>결과를 수동으로 복사해야 함</td><td>파일로 저장하고 팀에게 공유 가능</td></tr><tr><td>&quot;우리 팀 규칙대로 작성해줘&quot;</td><td>매번 규칙을 알려줘야 함</td><td>팀 규칙을 저장해두면 항상 반영</td></tr></tbody></table><h2 id="비유로-이해하기" tabindex="-1">비유로 이해하기 <a class="header-anchor" href="#비유로-이해하기" aria-label="Permalink to &quot;비유로 이해하기&quot;">​</a></h2><ul><li><strong>웹 AI = 콜센터 상담원</strong> — 전화할 때마다 새로운 상담원. 매번 상황을 처음부터 설명해야 하고, 직접 뭔가 해주지는 못합니다.</li><li><strong>Cowork = 옆자리 동료</strong> — 우리 팀 상황을 알고, 내 파일도 볼 수 있고, 직접 문서를 고쳐주기도 하는 똑똑한 동료.</li></ul><h2 id="cowork로-할-수-있는-것들" tabindex="-1">Cowork로 할 수 있는 것들 <a class="header-anchor" href="#cowork로-할-수-있는-것들" aria-label="Permalink to &quot;Cowork로 할 수 있는 것들&quot;">​</a></h2><ul><li><strong>문서 작성:</strong> 이메일, 보고서, 기획서, 제안서 초안 작성 및 퇴고</li><li><strong>데이터 정리:</strong> 엑셀/CSV 데이터를 읽고 분석하고 요약</li><li><strong>회의 지원:</strong> 회의록 정리, 액션 아이템 추출, 후속 이메일 작성</li><li><strong>번역 &amp; 요약:</strong> 긴 문서 핵심 요약, 다국어 번역</li><li><strong>자료 조사:</strong> 특정 주제에 대한 리서치와 정리</li><li><strong>반복 업무:</strong> 매주/매달 같은 형태의 보고서, 뉴스레터 등 자동화</li></ul><h2 id="cowork의-핵심-기능-3가지" tabindex="-1">Cowork의 핵심 기능 3가지 <a class="header-anchor" href="#cowork의-핵심-기능-3가지" aria-label="Permalink to &quot;Cowork의 핵심 기능 3가지&quot;">​</a></h2><h3 id="_1-projects-프로젝트" tabindex="-1">1. Projects (프로젝트) <a class="header-anchor" href="#_1-projects-프로젝트" aria-label="Permalink to &quot;1. Projects (프로젝트)&quot;">​</a></h3><p>업무별로 작업 공간을 분리할 수 있습니다. &quot;주간보고&quot; 프로젝트, &quot;거래처 관리&quot; 프로젝트처럼 나눠두면 각 맥락을 따로 관리할 수 있어요.</p><h3 id="_2-custom-instructions-맞춤-지시" tabindex="-1">2. Custom Instructions (맞춤 지시) <a class="header-anchor" href="#_2-custom-instructions-맞춤-지시" aria-label="Permalink to &quot;2. Custom Instructions (맞춤 지시)&quot;">​</a></h3><p>&quot;보고서는 항상 존댓말로, 표 포함, A4 2장 이내&quot; 같은 규칙을 미리 설정해두면 매번 말하지 않아도 알아서 반영합니다.</p><h3 id="_3-memory-기억" tabindex="-1">3. Memory (기억) <a class="header-anchor" href="#_3-memory-기억" aria-label="Permalink to &quot;3. Memory (기억)&quot;">​</a></h3><p>자주 사용하는 정보를 기억합니다. &quot;내 이름은 박지연이고 마케팅팀이야&quot;라고 한 번 말하면, 다음 대화에서도 기억하고 있어요.</p><div class="info custom-block"><p class="custom-block-title">안심하세요</p><p>코딩이나 프로그래밍 지식은 전혀 필요 없습니다. 평소에 동료에게 부탁하듯 말로 하면 됩니다.</p></div>',17)])])}const k=o(s,[["render",d]]);export{q as __pageData,k as default};
